1	package trustmanager
2	
3	import (
4		"fmt"
5		"os"
6	
7		"github.com/openshift/cert-manager-operator/api/operator/v1alpha1"
8		"github.com/openshift/cert-manager-operator/pkg/controller/common"
9	)
10	
11	func (r *Reconciler) reconcileTrustManagerDeployment(trustManager *v1alpha1.TrustManager) error {
12		if err := validateTrustManagerConfig(trustManager); err != nil {
13			return common.NewIrrecoverableError(err, "%s configuration validation failed", trustManager.GetName())
14		}
15	
16		resourceLabels := getResourceLabels(trustManager)
17		resourceAnnotations := getResourceAnnotations(trustManager)
18	
19		trustNamespace := getTrustNamespace(trustManager)
20		if err := r.validateTrustNamespace(trustNamespace); err != nil {
21			return common.NewIrrecoverableError(err, "trust namespace %q validation failed", trustNamespace)
22		}
23	
24		caBundleHash, err := r.createOrApplyDefaultCAPackageConfigMap(trustManager, resourceLabels, resourceAnnotations)
25		if err != nil {
26			r.log.Error(err, "failed to reconcile default CA package ConfigMap")
27			return err
28		}
29	
30		if err := r.createOrApplyServiceAccounts(trustManager, resourceLabels, resourceAnnotations); err != nil {
31			r.log.Error(err, "failed to reconcile serviceaccount resource")
32			return err
33		}
34	
35		if err := r.createOrApplyRBACResources(trustManager, resourceLabels, resourceAnnotations, trustNamespace); err != nil {
36			r.log.Error(err, "failed to reconcile RBAC resources")
37			return err
38		}
39	
40		if err := r.createOrApplyServices(trustManager, resourceLabels, resourceAnnotations); err != nil {
41			r.log.Error(err, "failed to reconcile service resources")
42			return err
43		}
44	
45		if err := r.createOrApplyIssuer(trustManager, resourceLabels, resourceAnnotations); err != nil {
46			r.log.Error(err, "failed to reconcile issuer resource")
47			return err
48		}
49	
50		if err := r.createOrApplyCertificate(trustManager, resourceLabels, resourceAnnotations); err != nil {
51			r.log.Error(err, "failed to reconcile certificate resource")
52			return err
53		}
54	
55		if err := r.createOrApplyDeployment(trustManager, resourceLabels, resourceAnnotations, caBundleHash); err != nil {
56			r.log.Error(err, "failed to reconcile deployment resource")
57			return err
58		}
59	
60		if err := r.createOrApplyValidatingWebhookConfiguration(trustManager, resourceLabels, resourceAnnotations); err != nil {
61			r.log.Error(err, "failed to reconcile validatingwebhookconfiguration resource")
62			return err
63		}
64	
65		if err := r.updateStatusObservedState(trustManager); err != nil {
66			return common.FromClientError(err, "failed to update status observed state")
67		}
68	
69		r.log.V(4).Info("finished reconciliation of trustmanager", "name", trustManager.GetName())
70		return nil
71	}
72	
73	// validateTrustNamespace validates that the trust namespace exists.
74	func (r *Reconciler) validateTrustNamespace(namespace string) error {
75		exists, err := r.namespaceExists(namespace)
76		if err != nil {
77			return fmt.Errorf("failed to check if namespace %q exists: %w", namespace, err)
78		}
79		if !exists {
80			return fmt.Errorf("trust namespace %q does not exist, create the namespace before creating TrustManager CR", namespace)
81		}
82		return nil
83	}
84	
85	// updateStatusObservedState populates and persists the TrustManager status with the observed state.
86	// Returns nil if no changes were needed, otherwise returns an error if the update fails.
87	func (r *Reconciler) updateStatusObservedState(trustManager *v1alpha1.TrustManager) error {
88		changed := false
89	
90		if image := os.Getenv(trustManagerImageNameEnvVarName); trustManager.Status.TrustManagerImage != image {
91			trustManager.Status.TrustManagerImage = image
92			changed = true
93		}
94	
95		if ns := getTrustNamespace(trustManager); trustManager.Status.TrustNamespace != ns {
96			trustManager.Status.TrustNamespace = ns
97			changed = true
98		}
99	
100		if policy := trustManager.Spec.TrustManagerConfig.SecretTargets.Policy; trustManager.Status.SecretTargetsPolicy != policy {
101			trustManager.Status.SecretTargetsPolicy = policy
102			changed = true
103		}
104	
105		if policy := trustManager.Spec.TrustManagerConfig.DefaultCAPackage.Policy; trustManager.Status.DefaultCAPackagePolicy != policy {
106			trustManager.Status.DefaultCAPackagePolicy = policy
107			changed = true
108		}
109	
110		if policy := trustManager.Spec.TrustManagerConfig.FilterExpiredCertificates; trustManager.Status.FilterExpiredCertificatesPolicy != policy {
111			trustManager.Status.FilterExpiredCertificatesPolicy = policy
112			changed = true
113		}
114	
115		if !changed {
116			return nil
117		}
118	
119		return r.updateStatus(r.ctx, trustManager)
120	}
