// updateProxyEnv sets HTTP_PROXY, HTTPS_PROXY, and NO_PROXY env vars on the
// trust-manager container from the cluster-wide Proxy/cluster object when the
// config.openshift.io/v1 Proxy API is available. On clusters without the API
// (e.g. MicroShift) this is a no-op.
func (r *Reconciler) updateProxyEnv(deployment *appsv1.Deployment) {
	if !r.proxyInformer.Applicable() {
		return
	}

	proxy, err := (*r.proxyInformer.InformerFactory).Config().V1().Proxies().Lister().Get("cluster")
	if err != nil {
		r.log.V(2).Info("unable to read cluster proxy settings, skipping proxy env configuration", "error", err)
		return
	}

	var envVars []corev1.EnvVar
	if proxy.Status.HTTPProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "HTTP_PROXY", Value: proxy.Status.HTTPProxy})
	}
	if proxy.Status.HTTPSProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "HTTPS_PROXY", Value: proxy.Status.HTTPSProxy})
	}
	if proxy.Status.NoProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "NO_PROXY", Value: proxy.Status.NoProxy})
	}

	if len(envVars) == 0 {
		return
	}

	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			deployment.Spec.Template.Spec.Containers[i].Env = append(deployment.Spec.Template.Spec.Containers[i].Env, envVars...)
			break
		}
	}
}
